#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char token[10];
    while(T--){
        int wk[6];
        for(int i=0;i<6;i++){
            scanf("%s", token);
            wk[i] = (token[0]=='W');
        }
        int hat = 0;
        for(int i=0;i<=3;i++) if(wk[i] && wk[i+1] && wk[i+2]){ hat=1; break; }
        printf(hat?"YES\n":"NO\n");
    }
    return 0;
}

