const fs = require('fs');
const tokens = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (tokens.length===0) process.exit(0);
let pos = 0;
const T = parseInt(tokens[pos++], 10);
let out = [];
for (let tc = 0; tc < T; tc++) {
  const wk = [];
  for (let i = 0; i < 6; i++) {
    wk.push(tokens[pos++] === 'W');
  }
  let hat = false;
  for (let i = 0; i <= 3; i++) {
    if (wk[i] && wk[i+1] && wk[i+2]) { hat = true; break; }
  }
  out.push(hat ? 'YES' : 'NO');
}
console.log(out.join('\n'));
